#!/usr/bin/env bash
# Generate <project-root>/.gitignore for a Tuist-managed project.
#
# Multi-module mode (--multi-module): also ignores *.xcodeproj and
# *.xcworkspace, which are regenerated by `tuist generate` on every run.
#
# Single-module mode (default): keeps *.xcodeproj and *.xcworkspace
# tracked, since Tuist is intended as a one-shot bootstrap and Xcode
# manages the project artefacts thereafter.
#
# Existing .gitignore is preserved (the script skips creation) so user
# additions never get overwritten.
set -euo pipefail

usage() {
  cat <<EOF
Usage: $(basename "$0") --project-root <dir> [--multi-module]

Generates <project-root>/.gitignore for a Tuist-managed iOS project.

Required:
  --project-root <dir>  Absolute path to the project root.

Options:
  --multi-module        Add Multi-module section (ignore *.xcodeproj /
                        *.xcworkspace). Default mode (single) keeps these
                        tracked so Xcode can manage the project after a
                        one-shot Tuist bootstrap.
  -h, --help            Show this help.

Existing .gitignore at <project-root> is preserved (no overwrite).
EOF
}

PROJECT_ROOT=""
MULTI_MODULE=0

while [[ $# -gt 0 ]]; do
  case "$1" in
    --project-root) PROJECT_ROOT="$2"; shift 2 ;;
    --multi-module) MULTI_MODULE=1;    shift   ;;
    -h|--help)      usage; exit 0 ;;
    *) echo "Unknown option: $1" >&2; usage >&2; exit 1 ;;
  esac
done

[[ -n "$PROJECT_ROOT" ]] || { echo "--project-root required" >&2; usage >&2; exit 1; }
[[ -d "$PROJECT_ROOT" ]] || { echo "Project root not a directory: $PROJECT_ROOT" >&2; exit 1; }

GITIGNORE_PATH="${PROJECT_ROOT}/.gitignore"

if [[ -e "$GITIGNORE_PATH" ]]; then
  echo "Skipped: ${GITIGNORE_PATH} (already exists, preserved)"
  exit 0
fi

cat > "$GITIGNORE_PATH" <<'EOF'
### macOS ###
# General
.DS_Store
.AppleDouble
.LSOverride

# Icon must end with two
Icon

# Thumbnails
._*

# Files that might appear in the root of a volume
.DocumentRevisions-V100
.fseventsd
.Spotlight-V100
.TemporaryItems
.Trashes
.VolumeIcon.icns
.com.apple.timemachine.donotpresent

# Directories potentially created on remote AFP share
.AppleDB
.AppleDesktop
Network Trash Folder
Temporary Items
.apdisk

### Xcode ###
# Xcode
#
# gitignore contributors: remember to update Global/Xcode.gitignore, Objective-C.gitignore & Swift.gitignore

## User settings
xcuserdata/

## compatibility with Xcode 8 and earlier (ignoring not required starting Xcode 9)
*.xcscmblueprint
*.xccheckout

## compatibility with Xcode 3 and earlier (ignoring not required starting Xcode 4)
build/
DerivedData/
*.moved-aside
*.pbxuser
!default.pbxuser
*.mode1v3
!default.mode1v3
*.mode2v3
!default.mode2v3
*.perspectivev3
!default.perspectivev3

### Xcode Patch ###
*.xcodeproj/*
!*.xcodeproj/project.pbxproj
!*.xcodeproj/xcshareddata/
!*.xcworkspace/contents.xcworkspacedata
/*.gcno
EOF

if [[ "$MULTI_MODULE" -eq 1 ]]; then
  cat >> "$GITIGNORE_PATH" <<'EOF'

### Projects (multi-module — regenerated by tuist generate) ###
*.xcodeproj
*.xcworkspace
EOF
fi

cat >> "$GITIGNORE_PATH" <<'EOF'

### Tuist derived files ###
graph.dot
Derived/

### Tuist managed dependencies ###
Tuist/.build

### Local ###
Local/
EOF

if [[ "$MULTI_MODULE" -eq 1 ]]; then
  echo "Created: ${GITIGNORE_PATH} (multi-module)"
else
  echo "Created: ${GITIGNORE_PATH} (single-module — *.xcodeproj/*.xcworkspace tracked)"
fi
